<?php declare(strict_types=1); namespace App\Domains\PetServices\Http\Controllers; use App\Domains\PetServices\Models\B2BPetStorefront; use App\Domains\PetServices\Models\B2BPetOrder; use Illuminate\Http\JsonResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\DB; use Illuminate\Support\Str; final class B2BPetController { public function storefronts(): JsonResponse { return response()->json(['success'=>true,'data'=>B2BPetStorefront::where('is_active',true)->where('is_verified',true)->paginate(20),'correlation_id'=>Str::uuid()]); } public function createStorefront(Request $r): JsonResponse { try { $this->authorize('createStorefront',B2BPetStorefront::class); $v=$r->validate(['company_name'=>'required','inn'=>'required|unique:b2b_pet_storefronts,inn','description'=>'nullable','service_categories'=>'nullable|json','wholesale_discount'=>'nullable|numeric|between:0,100','min_order_amount'=>'integer|min:1000']); $c=Str::uuid()->toString(); DB::transaction(fn()=>B2BPetStorefront::create(['uuid'=>Str::uuid(),'tenant_id'=>auth()->user()->tenant_id]+$v+['correlation_id'=>$c])); return response()->json(['success'=>true,'message'=>'Витрина создана','correlation_id'=>$c],201); } catch (\Exception $e) { return response()->json(['success'=>false,'message'=>'Ошибка','correlation_id'=>Str::uuid()],500); } } public function createOrder(Request $r): JsonResponse { try { $v=$r->validate(['b2b_pet_storefront_id'=>'required|exists:b2b_pet_storefronts,id','company_contact_person'=>'required','company_phone'=>'required','items_json'=>'required|json','total_amount'=>'required|numeric|min:1']); $c=Str::uuid()->toString(); DB::transaction(fn()=>B2BPetOrder::create(['uuid'=>Str::uuid(),'tenant_id'=>auth()->user()->tenant_id,'order_number'=>'B2B-'.Str::random(8),'commission_amount'=>(int)($v['total_amount']*0.14),'status'=>'pending']+$v+['correlation_id'=>$c])); return response()->json(['success'=>true,'message'=>'Заказ создан','correlation_id'=>$c],201); } catch (\Exception $e) { return response()->json(['success'=>false,'message'=>'Ошибка','correlation_id'=>Str::uuid()],500); } } public function myB2BOrders(): JsonResponse { return response()->json(['success'=>true,'data'=>B2BPetOrder::where('tenant_id',auth()->user()->tenant_id)->latest()->paginate(20),'correlation_id'=>Str::uuid()]); } public function approveOrder(int $id): JsonResponse { try { $o=B2BPetOrder::findOrFail($id); $this->authorize('approveOrder',$o); DB::transaction(fn()=>$o->update(['status'=>'approved'])); return response()->json(['success'=>true,'message'=>'Одобрено','correlation_id'=>Str::uuid()]); } catch (\Exception $e) { return response()->json(['success'=>false,'message'=>'Ошибка','correlation_id'=>Str::uuid()],500); } } public function rejectOrder(int $id,Request $r): JsonResponse { try { $o=B2BPetOrder::findOrFail($id); $this->authorize('rejectOrder',$o); DB::transaction(fn()=>$o->update(['status'=>'rejected','notes'=>$r->get('reason','')])); return response()->json(['success'=>true,'message'=>'Отклонено','correlation_id'=>Str::uuid()]); } catch (\Exception $e) { return response()->json(['success'=>false,'message'=>'Ошибка','correlation_id'=>Str::uuid()],500); } } public function verifyInn(int $id): JsonResponse { try { $this->authorize('verifyInn',B2BPetStorefront::class); DB::transaction(fn()=>B2BPetStorefront::findOrFail($id)->update(['is_verified'=>true])); return response()->json(['success'=>true,'message'=>'Верифицировано','correlation_id'=>Str::uuid()]); } catch (\Exception $e) { return response()->json(['success'=>false,'message'=>'Ошибка','correlation_id'=>Str::uuid()],500); } } }
